/* CISSP :: content/quiz7.js — CISSP Domain 7 question bank (100 items). */
window.CISSP = window.CISSP || {}; CISSP.questions = CISSP.questions || [];
CISSP.questions.push(
{ id:"D7-001", domain:7, obj:"7.1", diff:"easy", q:"A responder is collecting evidence from a live compromised server. Following the order of volatility, which data source should be captured FIRST?", options:["Archived logs on a backup tape","Configuration files on a network share","Data on the local hard disk","CPU cache and registers"], answer:3, explain:"<strong>CPU cache and registers</strong> are the most volatile data and disappear the instant process state changes, so the order of volatility says to capture them before less volatile sources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Archived logs on a backup tape</b>: archived media is the least volatile source and is captured last.</span><span class='qd'><b>Data on the local hard disk</b>: disk data persists after shutdown, so it is far lower in the order of volatility than CPU registers.</span><span class='qd'><b>Configuration files on a network share</b>: files on remote persistent storage are non-volatile and collected later.</span>" },
{ id:"D7-002", domain:7, obj:"7.1", diff:"medium", q:"An investigator wants collected evidence to be admissible in court. Which practice MOST directly preserves the chain of custody?", options:["Encrypting the disk image with a corporate key","Compressing the image to save storage space","Documenting every person who handled the evidence with time, date, and purpose","Storing the evidence on the compromised server"], answer:2, explain:"<strong>Documenting every person who handled the evidence with time, date, and purpose</strong> is the essence of chain of custody, proving the evidence was controlled and unaltered from seizure to court.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypting the disk image with a corporate key</b>: encryption protects confidentiality but does not record who handled the evidence.</span><span class='qd'><b>Compressing the image to save storage space</b>: compression is storage management and does nothing to establish custody.</span><span class='qd'><b>Storing the evidence on the compromised server</b>: leaving evidence on a compromised system risks tampering and destroys reliability.</span>" },
{ id:"D7-003", domain:7, obj:"7.1", diff:"medium", q:"Before analyzing a seized hard drive, a forensic examiner creates a bit-for-bit copy and calculates a hash of both the original and the copy. What is the PRIMARY purpose of the hash?", options:["To compress the image for faster analysis","To index the file system for keyword search","To encrypt the evidence during transport","To prove the copy is an exact, unaltered duplicate of the original"], answer:3, explain:"<strong>To prove the copy is an exact, unaltered duplicate of the original</strong> — matching hash values on the source and image demonstrate integrity, so analysis is performed on the copy while the original stays untouched.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To compress the image for faster analysis</b>: hashing does not reduce size; it produces a fixed-length fingerprint.</span><span class='qd'><b>To encrypt the evidence during transport</b>: a hash is one-way and provides integrity, not confidentiality.</span><span class='qd'><b>To index the file system for keyword search</b>: indexing is a separate analysis task unrelated to verifying duplication.</span>" },
{ id:"D7-004", domain:7, obj:"7.1", diff:"hard", q:"During an internal fraud investigation, an examiner powers on a suspect laptop, browses the file system with the built-in OS, and opens documents before imaging the disk. Why is this approach flawed?", options:["It is correct because live data should always be reviewed first","Documents cannot be opened without a write blocker","Booting the native OS alters timestamps and metadata, compromising evidence integrity","Imaging must always precede hashing"], answer:2, explain:"<strong>Booting the native OS alters timestamps and metadata, compromising evidence integrity</strong> — accessing files changes last-accessed times and can trigger writes, so examiners image first using a write blocker and analyze the copy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is correct because live data should always be reviewed first</b>: casually browsing with the native OS is not controlled live collection and destroys metadata.</span><span class='qd'><b>Documents cannot be opened without a write blocker</b>: they can be opened, but doing so on the original is exactly the mistake described.</span><span class='qd'><b>Imaging must always precede hashing</b>: the flaw here is altering the original, not a hashing sequence detail.</span>" },
{ id:"D7-005", domain:7, obj:"7.1", diff:"medium", q:"A company must preserve emails and documents because litigation is reasonably anticipated. What is the FIRST action management should take?", options:["Delete outdated records to reduce discovery scope","Encrypt all mailboxes company-wide","Migrate the mailboxes to a new archive vendor","Issue a legal hold suspending normal data destruction"], answer:3, explain:"<strong>Issue a legal hold suspending normal data destruction</strong> — once litigation is reasonably anticipated, the organization must halt routine deletion to avoid spoliation of relevant evidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete outdated records to reduce discovery scope</b>: destroying potentially relevant records after a duty to preserve arises is spoliation.</span><span class='qd'><b>Encrypt all mailboxes company-wide</b>: encryption protects confidentiality but does nothing to preserve records against deletion.</span><span class='qd'><b>Migrate the mailboxes to a new archive vendor</b>: a migration risks altering or losing data and is not the required preservation step.</span>" },
{ id:"D7-006", domain:7, obj:"7.1", diff:"hard", q:"An examiner must collect volatile artifacts from a running host: network connections, running processes, RAM contents, and routing tables. Which sequence BEST follows the order of volatility?", options:["RAM contents, running processes, network connections, routing tables","Routing tables, RAM contents, network connections, running processes","Running processes, network connections, routing tables, RAM contents","RAM contents, routing tables, running processes, network connections"], answer:0, explain:"<strong>RAM contents, running processes, network connections, routing tables</strong> orders collection from most to least volatile: memory changes constantly, then process state, then live connections, then routing tables which are comparatively stable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Routing tables, RAM contents, network connections, running processes</b>: this captures a relatively stable artifact first and defers RAM.</span><span class='qd'><b>Running processes, network connections, routing tables, RAM contents</b>: leaving RAM for last risks losing the most volatile data.</span><span class='qd'><b>RAM contents, routing tables, running processes, network connections</b>: it starts correctly but jumps to routing tables before process and connection state.</span>" },
{ id:"D7-007", domain:7, obj:"7.1", diff:"easy", q:"Which type of evidence is a duplicate that is admissible in place of the original because it accurately reproduces it, such as a verified forensic disk image?", options:["Hearsay evidence","Best evidence","Secondary (copy) evidence","Circumstantial evidence"], answer:2, explain:"<strong>Secondary (copy) evidence</strong> is a reproduction, such as a hash-verified forensic image, that can substitute for the original when the copy is shown to be accurate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hearsay evidence</b>: hearsay is second-hand statements offered for their truth and is generally inadmissible.</span><span class='qd'><b>Best evidence</b>: the best evidence rule favors the original; the image is the substitute, not the original.</span><span class='qd'><b>Circumstantial evidence</b>: circumstantial evidence implies a fact indirectly and does not describe a duplicate.</span>" },
{ id:"D7-008", domain:7, obj:"7.1", diff:"medium", q:"A forensic team is investigating a possible network intrusion. Which discipline focuses on capturing and analyzing packet captures and flow records to reconstruct attacker activity?", options:["Media forensics","Embedded device forensics","Software forensics","Network forensics"], answer:3, explain:"<strong>Network forensics</strong> examines packet captures, flow records, and connection logs to reconstruct how an intruder moved across the network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Media forensics</b>: media (disk) forensics recovers data from storage devices, not live network traffic.</span><span class='qd'><b>Software forensics</b>: software forensics analyzes code authorship and malware behavior, not network flows.</span><span class='qd'><b>Embedded device forensics</b>: this focuses on firmware and IoT/mobile devices, not packet-level reconstruction.</span>" },
{ id:"D7-009", domain:7, obj:"7.15", diff:"easy", q:"Which mechanism allows an employee under threat to silently signal for help while appearing to comply with an attacker's demands?", options:["A stronger password","A firewall rule","A backup job","A duress code (silent alarm)"], answer:3, explain:"<strong>A duress code (silent alarm)</strong> lets a coerced employee covertly alert security, for example by entering a special PIN that appears normal but triggers a silent response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A stronger password</b>: password strength does not signal coercion during an attack.</span><span class='qd'><b>A firewall rule</b>: a firewall governs network traffic, not personnel duress signaling.</span><span class='qd'><b>A backup job</b>: backups protect data and cannot alert responders to a coercion event.</span>" },
{ id:"D7-010", domain:7, obj:"7.1", diff:"easy", q:"Which of the following BEST describes admissible evidence?", options:["Evidence that is relevant, material, and legally obtained","Any evidence that supports the investigator's theory","Evidence that is only in electronic form","Evidence that has been compressed and encrypted"], answer:0, explain:"<strong>Evidence that is relevant, material, and legally obtained</strong> — to be admissible, evidence must relate to the case, be significant to a fact at issue, and be gathered lawfully.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Any evidence that supports the investigator's theory</b>: supporting a theory does not satisfy relevance, materiality, and lawful collection tests.</span><span class='qd'><b>Evidence that is only in electronic form</b>: admissibility applies to physical and digital evidence alike.</span><span class='qd'><b>Evidence that has been compressed and encrypted</b>: processing choices do not by themselves make evidence admissible.</span>" },
{ id:"D7-011", domain:7, obj:"7.2", diff:"easy", q:"Which system aggregates and correlates log data from many sources to detect security events and support investigations?", options:["DLP","Load balancer","VPN concentrator","SIEM"], answer:3, explain:"<strong>SIEM</strong> (Security Information and Event Management) centralizes, normalizes, and correlates logs from across the environment to surface security events and support forensics.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DLP</b>: Data Loss Prevention inspects and blocks sensitive data movement; it is not a log-correlation platform.</span><span class='qd'><b>VPN concentrator</b>: a VPN concentrator terminates encrypted tunnels and does not aggregate logs.</span><span class='qd'><b>Load balancer</b>: a load balancer distributes traffic and performs no security event correlation.</span>" },
{ id:"D7-012", domain:7, obj:"7.2", diff:"medium", q:"A SOC wants to automate repetitive triage such as enriching alerts and quarantining hosts by executing predefined playbooks. Which technology BEST fits?", options:["SIEM","IDS","SOAR","NAC"], answer:2, explain:"<strong>SOAR</strong> (Security Orchestration, Automation, and Response) runs playbooks to automate enrichment, containment, and other repetitive response actions across integrated tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SIEM</b>: a SIEM correlates and alerts on events but on its own does not execute automated response playbooks.</span><span class='qd'><b>IDS</b>: an IDS detects and alerts on suspicious traffic; it does not orchestrate responses.</span><span class='qd'><b>NAC</b>: Network Access Control enforces admission policies for devices, not playbook-driven automation.</span>" },
{ id:"D7-013", domain:7, obj:"7.2", diff:"medium", q:"An organization deploys a sensor that monitors traffic and can drop malicious packets inline before they reach the target. Which control is this?", options:["IDS (intrusion detection system)","Syslog server","Passive tap","IPS (intrusion prevention system)"], answer:3, explain:"<strong>IPS (intrusion prevention system)</strong> sits inline and can actively block or drop malicious traffic in real time, not merely alert on it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IDS (intrusion detection system)</b>: an IDS is typically out-of-band and only detects and alerts; it does not drop packets inline.</span><span class='qd'><b>Passive tap</b>: a tap copies traffic for monitoring and cannot block anything.</span><span class='qd'><b>Syslog server</b>: a syslog server collects log messages and performs no traffic inspection or blocking.</span>" },
{ id:"D7-014", domain:7, obj:"7.2", diff:"hard", q:"A security analyst wants to detect a privileged user who suddenly downloads gigabytes of data at 3 a.m. from an unusual location, even though no signature exists for this behavior. Which capability is BEST suited?", options:["Signature-based IDS","Static antivirus scanning","UEBA (user and entity behavior analytics)","A stateful firewall rule"], answer:2, explain:"<strong>UEBA (user and entity behavior analytics)</strong> baselines normal behavior for users and entities and flags anomalies such as off-hours mass downloads, catching threats no signature covers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signature-based IDS</b>: signatures match known patterns and cannot detect novel anomalous behavior.</span><span class='qd'><b>Static antivirus scanning</b>: AV scans files for known malware and does not model user behavior over time.</span><span class='qd'><b>A stateful firewall rule</b>: a firewall enforces connection policy but does not analyze behavioral baselines.</span>" },
{ id:"D7-015", domain:7, obj:"7.2", diff:"medium", q:"Multiple servers show inconsistent event times, making log correlation unreliable. Which control MOST directly fixes this?", options:["Enabling full-disk encryption","Adding more SIEM storage","Increasing the log retention period","Synchronizing all systems to a common NTP time source"], answer:3, explain:"<strong>Synchronizing all systems to a common NTP time source</strong> ensures consistent timestamps so events can be accurately correlated across hosts during an investigation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enabling full-disk encryption</b>: encryption protects data at rest and has no effect on timestamp consistency.</span><span class='qd'><b>Increasing the log retention period</b>: keeping logs longer does not correct misaligned clocks.</span><span class='qd'><b>Adding more SIEM storage</b>: more storage addresses capacity, not the underlying time-sync problem.</span>" },
{ id:"D7-016", domain:7, obj:"7.2", diff:"easy", q:"What is the primary security purpose of forwarding logs to a centralized, tightly controlled log server?", options:["To reduce disk usage on endpoints","To replace the need for backups","To speed up application performance","To preserve log integrity and prevent attackers from deleting local evidence"], answer:3, explain:"<strong>To preserve log integrity and prevent attackers from deleting local evidence</strong> — centralizing logs off the source host means an attacker who compromises a system cannot simply erase the record of their activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To reduce disk usage on endpoints</b>: freeing disk space is a minor side effect, not the security purpose.</span><span class='qd'><b>To speed up application performance</b>: log forwarding does not accelerate applications.</span><span class='qd'><b>To replace the need for backups</b>: centralized logging complements but does not replace data backups.</span>" },
{ id:"D7-017", domain:7, obj:"7.2", diff:"medium", q:"An IDS repeatedly alerts on legitimate administrator activity, overwhelming analysts. What is this condition called and the BEST first response?", options:["A true positive; escalate to management","A false negative; add more signatures","A false positive; tune the rule to reduce noise","A true negative; disable the IDS"], answer:2, explain:"<strong>A false positive; tune the rule to reduce noise</strong> — the IDS is flagging benign activity as malicious, so the correct step is to tune or whitelist the known-good behavior to cut alert fatigue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A true positive; escalate to management</b>: the activity is legitimate, so it is not a true positive.</span><span class='qd'><b>A false negative; add more signatures</b>: a false negative is a missed real attack, the opposite of noisy benign alerts.</span><span class='qd'><b>A true negative; disable the IDS</b>: a true negative is correctly ignoring benign traffic, and disabling the IDS removes needed visibility.</span>" },
{ id:"D7-018", domain:7, obj:"7.2", diff:"hard", q:"A security architect wants IDS coverage that can detect deviations from a learned normal traffic profile, accepting more false positives in exchange for catching novel attacks. Which detection method fits?", options:["Signature-based detection","Port-based access control","Blacklist-only filtering","Anomaly (behavior)-based detection"], answer:3, explain:"<strong>Anomaly (behavior)-based detection</strong> builds a baseline of normal activity and alerts on deviations, enabling detection of previously unseen attacks at the cost of more false positives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signature-based detection</b>: signatures only match known patterns and cannot flag novel behavior.</span><span class='qd'><b>Blacklist-only filtering</b>: blacklists block known-bad indicators and miss anything not already listed.</span><span class='qd'><b>Port-based access control</b>: filtering by port governs connectivity, not behavioral deviation.</span>" },
{ id:"D7-019", domain:7, obj:"7.2", diff:"medium", q:"Which log source would MOST directly reveal that a user account authenticated successfully from two countries within five minutes (impossible travel)?", options:["Printer spooler logs","DHCP lease logs","Authentication and sign-in logs","Backup completion logs"], answer:2, explain:"<strong>Authentication and sign-in logs</strong> record successful logon events with timestamps and source locations, which is exactly what reveals impossible-travel anomalies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Printer spooler logs</b>: these track print jobs and contain no sign-in geolocation data.</span><span class='qd'><b>DHCP lease logs</b>: DHCP logs show address assignments, not authentication origin countries.</span><span class='qd'><b>Backup completion logs</b>: backup logs report job status and are unrelated to sign-in location.</span>" },
{ id:"D7-020", domain:7, obj:"7.2", diff:"easy", q:"What does a log retention policy primarily define?", options:["How long log data is kept before being securely disposed of","Which firewall ports are open","The encryption algorithm for backups","The number of SOC analysts on shift"], answer:0, explain:"<strong>How long log data is kept before being securely disposed of</strong> — retention policy sets the required storage duration, balancing investigative need, compliance mandates, and storage cost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Which firewall ports are open</b>: port configuration is a network control, not a retention concept.</span><span class='qd'><b>The encryption algorithm for backups</b>: cipher selection is unrelated to how long logs are retained.</span><span class='qd'><b>The number of SOC analysts on shift</b>: staffing is operational, not a retention definition.</span>" },
{ id:"D7-021", domain:7, obj:"7.14", diff:"easy", q:"Which physical security control is designed to prevent tailgating, where an unauthorized person follows an authorized person through a secure door?", options:["A mantrap (access control vestibule)","A motion-activated light","A parking gate","A visitor logbook"], answer:0, explain:"<strong>A mantrap (access control vestibule)</strong> uses two interlocking doors so only one authenticated person passes at a time, directly preventing tailgating into a secure area.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A motion-activated light</b>: lighting deters some activity but does not physically stop a second person from following through a door.</span><span class='qd'><b>A parking gate</b>: a parking gate controls vehicles, not pedestrian tailgating through interior doors.</span><span class='qd'><b>A visitor logbook</b>: a logbook records visitors but cannot physically prevent tailgating.</span>" },
{ id:"D7-022", domain:7, obj:"7.3", diff:"easy", q:"What is the primary goal of establishing a secure baseline configuration for servers?", options:["To maximize the number of installed services","To let each administrator configure systems freely","To disable all logging","To define a known-good, consistent, hardened starting state for systems"], answer:3, explain:"<strong>To define a known-good, consistent, hardened starting state for systems</strong> — a baseline sets a documented secure configuration that all like systems must meet, enabling consistency and drift detection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To maximize the number of installed services</b>: more services expand the attack surface, the opposite of hardening.</span><span class='qd'><b>To disable all logging</b>: baselines typically require logging enabled, not disabled.</span><span class='qd'><b>To let each administrator configure systems freely</b>: free-form configuration causes drift, which baselines prevent.</span>" },
{ id:"D7-023", domain:7, obj:"7.3", diff:"medium", q:"An auditor finds that production servers have quietly diverged from their approved secure baseline over time. What is this phenomenon called?", options:["Configuration drift","Fault tolerance","Data remanence","Privilege creep"], answer:0, explain:"<strong>Configuration drift</strong> is the gradual, often undocumented divergence of systems from their approved baseline, reintroducing risk that hardening had removed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fault tolerance</b>: fault tolerance is a system's ability to keep operating despite failures.</span><span class='qd'><b>Data remanence</b>: data remanence is residual data left on media after deletion.</span><span class='qd'><b>Privilege creep</b>: privilege creep is the accumulation of excess access rights by users, not baseline drift.</span>" },
{ id:"D7-024", domain:7, obj:"7.3", diff:"medium", q:"Which practice ensures every deployed system reflects the approved configuration and that unauthorized changes can be identified and reverted?", options:["Ad hoc manual configuration by each admin","Disabling patch management","Automated configuration management with enforced baselines","Sharing one admin password across all servers"], answer:2, explain:"<strong>Automated configuration management with enforced baselines</strong> uses tooling to apply, monitor, and remediate configurations against the approved standard, catching and reverting unauthorized changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ad hoc manual configuration by each admin</b>: manual, inconsistent changes are the cause of drift, not a remedy.</span><span class='qd'><b>Disabling patch management</b>: turning off patching increases vulnerability and is unrelated to enforcing baselines.</span><span class='qd'><b>Sharing one admin password across all servers</b>: shared credentials weaken accountability and do not enforce configuration.</span>" },
{ id:"D7-025", domain:7, obj:"7.3", diff:"easy", q:"What does a configuration management database (CMDB) primarily track?", options:["Employee salary records","Only physical building floor plans","Marketing campaign metrics","Configuration items (CIs) and their relationships across the environment"], answer:3, explain:"<strong>Configuration items (CIs) and their relationships across the environment</strong> — a CMDB inventories assets and how they interrelate, supporting change, incident, and asset management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Employee salary records</b>: compensation data belongs in HR systems, not a CMDB.</span><span class='qd'><b>Marketing campaign metrics</b>: campaign analytics are business data unrelated to configuration items.</span><span class='qd'><b>Only physical building floor plans</b>: a CMDB tracks IT configuration items and relationships, not just floor plans.</span>" },
{ id:"D7-026", domain:7, obj:"7.3", diff:"hard", q:"A new zero-day exploit targets a specific service. To quickly identify which systems are exposed, which configuration management artifact is MOST valuable?", options:["The office seating chart","The annual budget spreadsheet","An accurate, current asset inventory tied to installed software versions","The visitor sign-in log"], answer:2, explain:"<strong>An accurate, current asset inventory tied to installed software versions</strong> lets responders instantly filter for systems running the vulnerable service and prioritize remediation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The office seating chart</b>: seating assignments say nothing about which systems run the affected software.</span><span class='qd'><b>The annual budget spreadsheet</b>: financial data cannot identify exposed hosts.</span><span class='qd'><b>The visitor sign-in log</b>: physical visitor records are irrelevant to software exposure.</span>" },
{ id:"D7-027", domain:7, obj:"7.3", diff:"medium", q:"To reduce the attack surface on a new server build, which baseline hardening action is MOST appropriate?", options:["Enable every optional service by default","Turn off audit logging","Grant all users administrative rights","Disable or remove unnecessary services, ports, and default accounts"], answer:3, explain:"<strong>Disable or remove unnecessary services, ports, and default accounts</strong> shrinks the attack surface by eliminating components an attacker could exploit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enable every optional service by default</b>: enabling extra services expands the attack surface.</span><span class='qd'><b>Grant all users administrative rights</b>: broad admin rights violate least privilege and increase risk.</span><span class='qd'><b>Turn off audit logging</b>: disabling logging removes the visibility needed to detect attacks.</span>" },
{ id:"D7-028", domain:7, obj:"7.4", diff:"easy", q:"The principle of least privilege states that a user or process should have which level of access?", options:["The maximum access available to avoid future requests","Access equal to that of their manager","Administrative access on all systems","Only the access required to perform assigned duties"], answer:3, explain:"<strong>Only the access required to perform assigned duties</strong> — least privilege minimizes what each identity can do, limiting damage from mistakes, misuse, or compromise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The maximum access available to avoid future requests</b>: granting excess access for convenience violates least privilege.</span><span class='qd'><b>Administrative access on all systems</b>: universal admin rights are the antithesis of least privilege.</span><span class='qd'><b>Access equal to that of their manager</b>: access should map to duties, not to another person's role.</span>" },
{ id:"D7-029", domain:7, obj:"7.4", diff:"medium", q:"A company splits the ability to initiate a payment from the ability to approve it so that no single employee can complete a fraudulent transaction alone. Which principle is being applied?", options:["Separation of duties","Job rotation","Mandatory vacation","Least privilege"], answer:0, explain:"<strong>Separation of duties</strong> divides a sensitive task among multiple people so that fraud requires collusion, as with splitting payment initiation from approval.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Job rotation</b>: job rotation moves people between roles to detect fraud and cross-train, but does not split a single transaction.</span><span class='qd'><b>Mandatory vacation</b>: mandatory vacation forces time off to surface hidden schemes, not to split a task.</span><span class='qd'><b>Least privilege</b>: least privilege limits access level but does not require two people for one transaction.</span>" },
{ id:"D7-030", domain:7, obj:"7.4", diff:"medium", q:"An organization requires finance employees to take at least one continuous week of vacation each year. What is the PRIMARY security rationale?", options:["To improve employee morale only","To reduce payroll costs","To increase the chance that concealed fraudulent activity surfaces while the person is away","To free up parking spaces"], answer:2, explain:"<strong>To increase the chance that concealed fraudulent activity surfaces while the person is away</strong> — mandatory vacation forces a substitute to handle the duties, which can expose ongoing schemes that require the perpetrator's daily involvement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve employee morale only</b>: morale may benefit, but the security purpose is fraud detection.</span><span class='qd'><b>To reduce payroll costs</b>: vacation does not reduce salary costs.</span><span class='qd'><b>To free up parking spaces</b>: this is irrelevant to the control's purpose.</span>" },
{ id:"D7-031", domain:7, obj:"7.4", diff:"medium", q:"Rotating employees through different roles over time helps detect fraud and reduces dependence on any single person. What is this control called?", options:["Least privilege","Need to know","Job rotation","Dual control"], answer:2, explain:"<strong>Job rotation</strong> periodically moves staff between duties, which cross-trains personnel and increases the likelihood that irregularities left by a predecessor are discovered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Least privilege</b>: least privilege limits access scope; it does not move people between roles.</span><span class='qd'><b>Need to know</b>: need to know restricts access to information required for a task, not role rotation.</span><span class='qd'><b>Dual control</b>: dual control requires two people simultaneously for one action, which is different from rotating roles.</span>" },
{ id:"D7-032", domain:7, obj:"7.4", diff:"hard", q:"A single senior engineer holds standing domain admin, database admin, and backup operator rights accumulated over years across role changes. Which two principles are MOST violated, and what is the fix?", options:["Least privilege and separation of duties; review and right-size access to current duties","Fault tolerance and RAID; add another disk","Data remanence and sanitization; wipe the disks","Nonrepudiation and hashing; sign the logs"], answer:0, explain:"<strong>Least privilege and separation of duties; review and right-size access to current duties</strong> — accumulated cross-role rights are privilege creep that concentrate too much power in one person, so an access review should strip rights no longer needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fault tolerance and RAID; add another disk</b>: these address availability of storage, not excessive access rights.</span><span class='qd'><b>Data remanence and sanitization; wipe the disks</b>: remanence concerns residual data on media, not permissions.</span><span class='qd'><b>Nonrepudiation and hashing; sign the logs</b>: nonrepudiation ensures actions cannot be denied and does not address privilege accumulation.</span>" },
{ id:"D7-033", domain:7, obj:"7.4", diff:"medium", q:"Which practice ensures a user is granted access only to the specific information required for their task, even within a classification level they are cleared for?", options:["Need to know","Job rotation","Mandatory vacation","Clipping level"], answer:0, explain:"<strong>Need to know</strong> restricts access to only the specific data required for a duty, so clearance alone does not grant access to everything at that level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Job rotation</b>: job rotation moves people between roles and does not govern granular data access.</span><span class='qd'><b>Mandatory vacation</b>: mandatory vacation is a fraud-detection control, not an access restriction.</span><span class='qd'><b>Clipping level</b>: a clipping level is a threshold for triggering alerts, unrelated to data access scope.</span>" },
{ id:"D7-034", domain:7, obj:"7.4", diff:"easy", q:"Two authorized individuals must both act together to perform a highly sensitive operation, such as launching a critical process. What is this control called?", options:["Dual control (two-person integrity)","Single sign-on","Least privilege","Job rotation"], answer:0, explain:"<strong>Dual control (two-person integrity)</strong> requires two authorized people to act simultaneously, ensuring no single individual can carry out a highly sensitive operation alone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single sign-on</b>: SSO simplifies authentication across systems and does not require two people.</span><span class='qd'><b>Least privilege</b>: least privilege limits access scope but does not mandate simultaneous dual action.</span><span class='qd'><b>Job rotation</b>: job rotation cycles staff through roles rather than requiring two people at once.</span>" },
{ id:"D7-035", domain:7, obj:"7.4", diff:"medium", q:"Privileged accounts such as domain administrators warrant extra controls. Which practice BEST reduces the risk of standing privileged access being abused?", options:["Grant permanent admin rights to reduce ticket volume","Share the admin account among the team","Use just-in-time privileged access that is time-limited and monitored","Disable logging on privileged sessions"], answer:2, explain:"<strong>Use just-in-time privileged access that is time-limited and monitored</strong> — granting elevated rights only when needed and for a limited window shrinks the exposure window and improves accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grant permanent admin rights to reduce ticket volume</b>: standing privilege maximizes the abuse window and violates least privilege.</span><span class='qd'><b>Share the admin account among the team</b>: shared accounts destroy individual accountability.</span><span class='qd'><b>Disable logging on privileged sessions</b>: removing logging eliminates the oversight most needed for privileged access.</span>" },
{ id:"D7-036", domain:7, obj:"7.4", diff:"hard", q:"Separation of duties is difficult to enforce in a small team because one person must perform multiple conflicting duties. Which compensating control is MOST appropriate?", options:["Ignore the conflict since the team is small","Remove all logging to simplify operations","Grant that person full administrative rights","Implement detective controls such as independent review and detailed activity logging of the conflicting duties"], answer:3, explain:"<strong>Implement detective controls such as independent review and detailed activity logging of the conflicting duties</strong> — when separation is impractical, compensating detective controls and independent oversight reduce the residual risk of the combined duties.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the conflict since the team is small</b>: accepting an unmanaged conflict leaves the fraud risk fully open.</span><span class='qd'><b>Grant that person full administrative rights</b>: broadening access worsens the concentration-of-power risk.</span><span class='qd'><b>Remove all logging to simplify operations</b>: removing logging eliminates the oversight a compensating control needs.</span>" },
{ id:"D7-037", domain:7, obj:"7.14", diff:"easy", q:"Which internal physical control ensures that only authorized personnel can enter a restricted server room?", options:["A public lobby with open access","An unlocked propped door","Badge-controlled door locks with logging","A welcome mat"], answer:2, explain:"<strong>Badge-controlled door locks with logging</strong> restrict entry to authorized badge holders and record who entered and when, providing both prevention and an audit trail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A public lobby with open access</b>: open access provides no restriction to the server room.</span><span class='qd'><b>An unlocked propped door</b>: a propped door defeats access control entirely.</span><span class='qd'><b>A welcome mat</b>: a welcome mat offers no access control.</span>" },
{ id:"D7-038", domain:7, obj:"7.5", diff:"easy", q:"Which term describes residual data that remains on storage media after it has been deleted or reformatted?", options:["Data remanence","Data sovereignty","Data classification","Data masking"], answer:0, explain:"<strong>Data remanence</strong> is the leftover representation of data that persists on media after ordinary deletion or formatting, which is why proper sanitization is required.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data sovereignty</b>: sovereignty concerns which jurisdiction's laws govern data, not residual media contents.</span><span class='qd'><b>Data classification</b>: classification assigns sensitivity labels and is unrelated to leftover data.</span><span class='qd'><b>Data masking</b>: masking obscures values in use or display; it does not describe residue on media.</span>" },
{ id:"D7-039", domain:7, obj:"7.5", diff:"hard", q:"A batch of solid-state drives (SSDs) that stored confidential data will be reused internally. Considering how SSDs manage storage, which sanitization method is MOST reliable?", options:["A single-pass overwrite of all logical blocks","Formatting the drive with the OS","Cryptographic erase (destroying the encryption key) or the drive's secure-erase command","Degaussing the SSD"], answer:2, explain:"<strong>Cryptographic erase (destroying the encryption key) or the drive's secure-erase command</strong> — SSD wear-leveling means overwrites may not reach all physical cells, so key destruction on a self-encrypting drive or ATA secure-erase reliably renders data unrecoverable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single-pass overwrite of all logical blocks</b>: wear-leveling can leave data in spare cells the overwrite never touches.</span><span class='qd'><b>Formatting the drive with the OS</b>: a format clears file tables but leaves the underlying data recoverable.</span><span class='qd'><b>Degaussing the SSD</b>: degaussing erases magnetic media; SSDs are flash-based, so degaussing does nothing.</span>" },
{ id:"D7-040", domain:7, obj:"7.5", diff:"medium", q:"A stack of failed magnetic hard drives that held top-secret data must be sanitized so data cannot be recovered by any means before disposal. Which method provides the HIGHEST assurance?", options:["Deleting the files and emptying the recycle bin","Renaming the files","Physical destruction (shredding/pulverizing) or degaussing","Compressing the drive contents"], answer:2, explain:"<strong>Physical destruction (shredding/pulverizing) or degaussing</strong> provides the highest assurance for high-sensitivity magnetic media, destroying the medium or its magnetic domains so recovery is infeasible.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deleting the files and emptying the recycle bin</b>: deletion only removes pointers; the data remains recoverable.</span><span class='qd'><b>Renaming the files</b>: renaming changes labels but leaves the underlying data intact.</span><span class='qd'><b>Compressing the drive contents</b>: compression reduces size but does not remove the data.</span>" },
{ id:"D7-041", domain:7, obj:"7.5", diff:"medium", q:"An organization plans to donate old workstations to a school. Which action BEST protects confidentiality while allowing reuse?", options:["Quick format only","Remove the monitors","Purge the drives with a validated overwrite or secure-erase and verify","Delete user profiles manually"], answer:2, explain:"<strong>Purge the drives with a validated overwrite or secure-erase and verify</strong> — purging renders data unrecoverable while leaving the drive usable for donation, and verification confirms success.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Quick format only</b>: a quick format leaves data recoverable and does not adequately sanitize.</span><span class='qd'><b>Remove the monitors</b>: monitors do not store the confidential data on the drives.</span><span class='qd'><b>Delete user profiles manually</b>: deleting profiles leaves residual data across the disk recoverable.</span>" },
{ id:"D7-042", domain:7, obj:"7.5", diff:"easy", q:"What is the primary goal of resource protection in security operations?", options:["To ensure hardware, software, and media assets are safeguarded throughout their lifecycle","To increase marketing reach","To reduce the number of employees","To eliminate the need for backups"], answer:0, explain:"<strong>To ensure hardware, software, and media assets are safeguarded throughout their lifecycle</strong> — resource protection covers provisioning, secure handling, and eventual sanitization or disposal of assets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase marketing reach</b>: marketing is a business function unrelated to protecting operational assets.</span><span class='qd'><b>To reduce the number of employees</b>: staffing decisions are not the aim of resource protection.</span><span class='qd'><b>To eliminate the need for backups</b>: backups remain essential; resource protection does not remove them.</span>" },
{ id:"D7-043", domain:7, obj:"7.5", diff:"medium", q:"When a cloud tenant deletes data, the underlying physical media is shared and cannot be physically destroyed by the customer. Which sanitization approach is the provider MOST likely to rely on?", options:["Degaussing the customer's virtual disk","Formatting the hypervisor","Shredding the physical drive per customer","Cryptographic erasure by destroying the tenant's encryption keys"], answer:3, explain:"<strong>Cryptographic erasure by destroying the tenant's encryption keys</strong> — because media is multi-tenant, providers encrypt tenant data and render it unrecoverable by destroying the keys, a scalable equivalent to destruction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Degaussing the customer's virtual disk</b>: a virtual disk has no magnetic domains to degauss.</span><span class='qd'><b>Shredding the physical drive per customer</b>: shared drives serve many tenants and cannot be shredded for one customer.</span><span class='qd'><b>Formatting the hypervisor</b>: formatting the hypervisor would disrupt all tenants and is not a data-sanitization method.</span>" },
{ id:"D7-044", domain:7, obj:"7.6", diff:"easy", q:"Which sequence correctly lists the phases of incident management in order?", options:["Detection, Response, Mitigation, Reporting, Recovery, Remediation, Lessons Learned","Recovery, Detection, Response, Reporting, Mitigation, Remediation, Lessons Learned","Response, Detection, Reporting, Recovery, Mitigation, Remediation, Lessons Learned","Detection, Reporting, Recovery, Response, Mitigation, Lessons Learned, Remediation"], answer:0, explain:"<strong>Detection, Response, Mitigation, Reporting, Recovery, Remediation, Lessons Learned</strong> is the ISC2 incident management order: you detect, respond, contain (mitigate), report, recover, remediate root cause, then learn.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery, Detection, Response, Reporting, Mitigation, Remediation, Lessons Learned</b>: you cannot recover before detecting and responding.</span><span class='qd'><b>Response, Detection, Reporting, Recovery, Mitigation, Remediation, Lessons Learned</b>: response cannot precede detection.</span><span class='qd'><b>Detection, Reporting, Recovery, Response, Mitigation, Lessons Learned, Remediation</b>: recovery here precedes response and mitigation, which is out of order.</span>" },
{ id:"D7-045", domain:7, obj:"7.6", diff:"medium", q:"During an active ransomware outbreak, responders isolate affected hosts from the network to stop the malware spreading. Which incident phase does this represent?", options:["Detection","Remediation","Lessons learned","Mitigation (containment)"], answer:3, explain:"<strong>Mitigation (containment)</strong> — isolating infected hosts limits the damage and prevents the incident from spreading while investigation continues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection</b>: detection is recognizing an incident is occurring, which has already happened.</span><span class='qd'><b>Lessons learned</b>: lessons learned is the post-incident review, not containing an active outbreak.</span><span class='qd'><b>Remediation</b>: remediation addresses root cause after containment, not the immediate isolation.</span>" },
{ id:"D7-046", domain:7, obj:"7.6", diff:"medium", q:"After containing and eradicating malware, the team rebuilds affected servers, applies missing patches, and eliminates the vulnerability that allowed entry. Which phase is this?", options:["Detection","Reporting","Remediation","Response"], answer:2, explain:"<strong>Remediation</strong> — this phase removes the underlying cause, such as unpatched vulnerabilities, so the same incident cannot recur.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection</b>: detection is the initial identification of the incident, already completed.</span><span class='qd'><b>Reporting</b>: reporting is communicating status to stakeholders, not fixing root cause.</span><span class='qd'><b>Response</b>: response is the initial action to an alert; remediation is the later root-cause fix.</span>" },
{ id:"D7-047", domain:7, obj:"7.6", diff:"easy", q:"Which incident management phase focuses on holding a review to capture what went well, what failed, and how to improve future response?", options:["Detection","Recovery","Mitigation","Lessons learned"], answer:3, explain:"<strong>Lessons learned</strong> is the post-incident phase where the team analyzes the response to improve procedures, controls, and readiness for the future.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection</b>: detection identifies that an incident is happening, not a retrospective review.</span><span class='qd'><b>Mitigation</b>: mitigation contains active damage during the incident, not afterward.</span><span class='qd'><b>Recovery</b>: recovery restores normal operations; it is not the review of the response.</span>" },
{ id:"D7-048", domain:7, obj:"7.6", diff:"medium", q:"A junior analyst notices anomalous outbound traffic but is unsure whether it is a real incident. What should happen FIRST according to good incident management?", options:["Immediately wipe the affected server","Begin lessons learned","Publish a press release","Detect and triage the event to confirm whether it is a genuine incident"], answer:3, explain:"<strong>Detect and triage the event to confirm whether it is a genuine incident</strong> — the detection phase includes validating and classifying the event before escalating a full response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately wipe the affected server</b>: wiping destroys evidence and precedes any confirmation or containment planning.</span><span class='qd'><b>Publish a press release</b>: external communication is premature before the event is even confirmed.</span><span class='qd'><b>Begin lessons learned</b>: a retrospective cannot occur before the incident is even identified.</span>" },
{ id:"D7-049", domain:7, obj:"7.6", diff:"hard", q:"During a breach, the CSIRT must decide between immediately shutting down a compromised system to stop exfiltration and keeping it running to gather live forensic evidence. Which factor MOST appropriately drives this decision?", options:["Whichever option the newest analyst prefers","Always keep systems running regardless of harm","The organization's documented IR priorities balancing evidence preservation against ongoing harm","Always power off immediately regardless of evidence needs"], answer:2, explain:"<strong>The organization's documented IR priorities balancing evidence preservation against ongoing harm</strong> — the IR plan should predefine whether stopping the bleeding or preserving live evidence takes precedence given business and legal context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whichever option the newest analyst prefers</b>: ad hoc individual preference is not a defensible basis for a high-stakes decision.</span><span class='qd'><b>Always keep systems running regardless of harm</b>: an absolute rule ignores cases where ongoing exfiltration causes greater damage.</span><span class='qd'><b>Always power off immediately regardless of evidence needs</b>: an absolute rule can destroy volatile evidence needed for prosecution.</span>" },
{ id:"D7-050", domain:7, obj:"7.6", diff:"medium", q:"Which document defines roles, escalation paths, and step-by-step procedures the team follows when a security incident occurs?", options:["Acceptable use policy","Data classification schema","Marketing plan","Incident response plan"], answer:3, explain:"<strong>Incident response plan</strong> lays out the roles, communication and escalation paths, and detailed procedures the CSIRT follows during an incident.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Acceptable use policy</b>: an AUP governs user behavior, not incident response steps.</span><span class='qd'><b>Marketing plan</b>: a marketing plan is unrelated to incident handling.</span><span class='qd'><b>Data classification schema</b>: a classification schema labels data sensitivity but does not describe response procedures.</span>" },
{ id:"D7-051", domain:7, obj:"7.6", diff:"easy", q:"What is the primary objective of the recovery phase of incident management?", options:["To identify the attacker's motive","To rewrite the security policy","To assign legal blame","To restore affected systems and services to normal, verified operation"], answer:3, explain:"<strong>To restore affected systems and services to normal, verified operation</strong> — recovery returns the environment to business-as-usual while confirming that systems are clean and functioning correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To identify the attacker's motive</b>: attribution and motive analysis are investigative, not the purpose of recovery.</span><span class='qd'><b>To assign legal blame</b>: assigning blame is a legal or HR matter outside recovery.</span><span class='qd'><b>To rewrite the security policy</b>: policy changes may come from lessons learned, not the recovery phase.</span>" },
{ id:"D7-052", domain:7, obj:"7.6", diff:"medium", q:"Which incident phase involves notifying appropriate internal stakeholders, and where required, regulators or law enforcement, about the incident?", options:["Detection","Remediation","Mitigation","Reporting"], answer:3, explain:"<strong>Reporting</strong> is the phase where the organization communicates the incident to management, affected parties, regulators, or law enforcement as legal and policy obligations require.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Detection</b>: detection identifies the incident but is not the stakeholder-notification phase.</span><span class='qd'><b>Mitigation</b>: mitigation contains the incident; it is not the act of formal reporting.</span><span class='qd'><b>Remediation</b>: remediation fixes root cause and is distinct from notifying stakeholders.</span>" },
{ id:"D7-053", domain:7, obj:"7.6", diff:"hard", q:"An organization suffers a breach of regulated personal data. The team has contained it and is drafting notifications. Which consideration is MOST important during the reporting phase?", options:["Choosing the cheapest notification method","Meeting legally mandated breach-notification timelines and content requirements","Delaying notification indefinitely to avoid reputational harm","Sending notifications only to the marketing list"], answer:1, explain:"<strong>Meeting legally mandated breach-notification timelines and content requirements</strong> — regulations such as GDPR impose strict deadlines and required content, and failing to comply brings penalties beyond the breach itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choosing the cheapest notification method</b>: cost is secondary to satisfying legal obligations.</span><span class='qd'><b>Delaying notification indefinitely to avoid reputational harm</b>: intentional delay violates mandated timelines and increases liability.</span><span class='qd'><b>Sending notifications only to the marketing list</b>: notifications must reach the actual affected data subjects and required authorities.</span>" },
{ id:"D7-054", domain:7, obj:"7.14", diff:"medium", q:"An organization installs bollards and reinforced planters around the entrance of its headquarters. Which threat are these controls MOST directly designed to mitigate?", options:["Phishing emails","SQL injection","Insider data theft","Vehicle-ramming attacks against the building"], answer:3, explain:"<strong>Vehicle-ramming attacks against the building</strong> — bollards and reinforced planters are crash-rated barriers that stop a vehicle from being driven into a building or crowd.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Phishing emails</b>: phishing is a social-engineering threat unrelated to physical vehicle barriers.</span><span class='qd'><b>SQL injection</b>: SQL injection is an application attack, not a physical intrusion.</span><span class='qd'><b>Insider data theft</b>: bollards do nothing to stop an insider exfiltrating data electronically.</span>" },
{ id:"D7-055", domain:7, obj:"7.14", diff:"hard", q:"A CISO wants CPTED (Crime Prevention Through Environmental Design) applied to a new campus. Which measure BEST reflects CPTED's natural surveillance concept?", options:["Installing a taller razor-wire fence only","Adding more server encryption","Requiring longer passwords","Designing landscaping, lighting, and window placement so occupants can naturally observe entry points"], answer:3, explain:"<strong>Designing landscaping, lighting, and window placement so occupants can naturally observe entry points</strong> — CPTED's natural surveillance uses the built environment to maximize visibility, deterring intruders who prefer not to be seen.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Installing a taller razor-wire fence only</b>: a fence is a barrier control, not the natural surveillance concept of CPTED.</span><span class='qd'><b>Adding more server encryption</b>: encryption is a logical control unrelated to environmental design.</span><span class='qd'><b>Requiring longer passwords</b>: password strength is an authentication control, not physical CPTED.</span>" },
{ id:"D7-056", domain:7, obj:"7.14", diff:"medium", q:"A facility deploys CCTV cameras with recording at all entrances. Into which control category do these cameras PRIMARILY fall?", options:["Preventive control","Detective control","Corrective control","A compensating control that patches software"], answer:1, explain:"<strong>Detective control</strong> — CCTV recording identifies and documents events after or as they occur, supporting detection and investigation rather than preventing entry.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive control</b>: cameras primarily record; they do not physically prevent entry, though they may deter.</span><span class='qd'><b>Corrective control</b>: corrective controls restore systems after an incident, which cameras do not do.</span><span class='qd'><b>A compensating control that patches software</b>: cameras are physical and do not patch software.</span>" },
{ id:"D7-057", domain:7, obj:"7.14", diff:"medium", q:"A secure facility places its most sensitive assets in the innermost zone, surrounded by progressively less sensitive areas. Which physical security concept does this reflect?", options:["Security zones (concentric layers)","Flat network design","Single-factor authentication","Open floor plan"], answer:0, explain:"<strong>Security zones (concentric layers)</strong> arrange controls in rings of increasing protection toward the most sensitive core, forcing an intruder to defeat multiple layers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Flat network design</b>: a flat design lacks layered segmentation, the opposite of concentric zones.</span><span class='qd'><b>Single-factor authentication</b>: this is a logical access concept, not a physical zoning model.</span><span class='qd'><b>Open floor plan</b>: an open plan removes internal barriers rather than layering them.</span>" },
{ id:"D7-058", domain:7, obj:"7.7", diff:"easy", q:"A decoy system deliberately exposed to attract and study attackers, containing no real production data, is called a:", options:["Honeypot","Load balancer","Proxy server","Domain controller"], answer:0, explain:"<strong>Honeypot</strong> is a decoy designed to lure attackers so their techniques can be observed and legitimate systems alerted, without exposing real data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Load balancer</b>: a load balancer distributes traffic; it is not a decoy for attackers.</span><span class='qd'><b>Proxy server</b>: a proxy forwards and filters requests and is not designed as bait.</span><span class='qd'><b>Domain controller</b>: a domain controller authenticates users and is a genuine production asset.</span>" },
{ id:"D7-059", domain:7, obj:"7.7", diff:"medium", q:"Which approach permits ONLY explicitly approved applications to run and blocks everything else by default?", options:["Blacklisting","Application whitelisting (allow listing)","Graylisting email","Port forwarding"], answer:1, explain:"<strong>Application whitelisting (allow listing)</strong> denies by default and allows only approved software to execute, which is far more effective than trying to enumerate every bad program.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blacklisting</b>: blacklisting blocks known-bad items but allows anything not listed, missing novel malware.</span><span class='qd'><b>Graylisting email</b>: graylisting temporarily defers unknown email senders, unrelated to application execution.</span><span class='qd'><b>Port forwarding</b>: port forwarding routes network traffic and does not control which applications run.</span>" },
{ id:"D7-060", domain:7, obj:"7.7", diff:"medium", q:"A security team runs a suspicious executable in an isolated, instrumented environment to observe its behavior without risking production. What is this technique called?", options:["Sandboxing","Load balancing","Clustering","Sharding"], answer:0, explain:"<strong>Sandboxing</strong> executes untrusted code in a contained environment so its behavior can be analyzed safely, isolating any malicious effects from real systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Load balancing</b>: load balancing spreads traffic across servers and does not isolate untrusted code.</span><span class='qd'><b>Clustering</b>: clustering groups servers for availability, not for safe malware analysis.</span><span class='qd'><b>Sharding</b>: sharding partitions data across databases and has nothing to do with isolating code.</span>" },
{ id:"D7-061", domain:7, obj:"7.7", diff:"hard", q:"An organization deploys a network of decoy hosts and fake credentials across its internal network to detect lateral movement early. Beyond a single honeypot, what is this called, and its main detective value?", options:["A honeynet; any interaction with the decoys is a high-fidelity indicator of intrusion","A honeypot cluster; it increases production throughput","A DMZ; it hosts public web servers","A CDN; it caches content globally"], answer:0, explain:"<strong>A honeynet; any interaction with the decoys is a high-fidelity indicator of intrusion</strong> — because no legitimate user should touch the decoys or fake credentials, any access is a strong, low-false-positive signal of an intruder moving laterally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A honeypot cluster; it increases production throughput</b>: decoys carry no production load and do not improve throughput.</span><span class='qd'><b>A DMZ; it hosts public web servers</b>: a DMZ is a segmented zone for public services, not a deception network.</span><span class='qd'><b>A CDN; it caches content globally</b>: a CDN accelerates content delivery and has no detective role.</span>" },
{ id:"D7-062", domain:7, obj:"7.7", diff:"easy", q:"Which control is BEST classified as preventive rather than detective?", options:["Security camera footage review","A firewall that blocks unauthorized inbound connections","An IDS alert log","An audit trail"], answer:1, explain:"<strong>A firewall that blocks unauthorized inbound connections</strong> is preventive because it stops unwanted activity before it occurs, whereas detective controls identify activity after the fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Security camera footage review</b>: reviewing footage detects events after they happen, making it detective.</span><span class='qd'><b>An IDS alert log</b>: an IDS detects and records suspicious activity rather than preventing it.</span><span class='qd'><b>An audit trail</b>: an audit trail is a detective record of past actions, not a preventive barrier.</span>" },
{ id:"D7-063", domain:7, obj:"7.7", diff:"medium", q:"A next-generation endpoint tool blocks any executable not on an approved list and detonates unknown files in an isolated environment before allowing them. Which two controls are combined?", options:["Application whitelisting and sandboxing","RAID and clustering","Degaussing and shredding","Job rotation and mandatory vacation"], answer:0, explain:"<strong>Application whitelisting and sandboxing</strong> — allow-listing blocks unapproved executables while sandbox detonation safely evaluates unknown files, layering prevention with dynamic analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID and clustering</b>: these are availability technologies, not execution-control measures.</span><span class='qd'><b>Degaussing and shredding</b>: these are media sanitization methods, unrelated to endpoint execution control.</span><span class='qd'><b>Job rotation and mandatory vacation</b>: these are personnel controls, not technical file-execution controls.</span>" },
{ id:"D7-064", domain:7, obj:"7.14", diff:"hard", q:"During an emergency evacuation of a data center, which principle takes ABSOLUTE priority over all others?", options:["Protecting the servers first","Preserving log integrity","Human safety and life","Minimizing downtime costs"], answer:2, explain:"<strong>Human safety and life</strong> — in any emergency, the protection of people always takes precedence over assets, data, or uptime.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Protecting the servers first</b>: equipment is replaceable; human life is not, so servers never come before people.</span><span class='qd'><b>Preserving log integrity</b>: log preservation matters but never above human safety.</span><span class='qd'><b>Minimizing downtime costs</b>: financial concerns are always subordinate to protecting life.</span>" },
{ id:"D7-065", domain:7, obj:"7.7", diff:"hard", q:"Legal counsel warns that a honeypot must be carefully scoped. Which concern is MOST relevant to how a honeypot is deployed and used?", options:["It might improve backup speeds","Enticement versus entrapment and potential liability if used to induce crimes","It reduces the need for firewalls","It automatically patches vulnerabilities"], answer:1, explain:"<strong>Enticement versus entrapment and potential liability if used to induce crimes</strong> — a honeypot may lawfully entice an attacker already intent on wrongdoing, but using it to induce someone to commit a crime they otherwise would not raises entrapment concerns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It might improve backup speeds</b>: honeypots have no bearing on backup performance.</span><span class='qd'><b>It reduces the need for firewalls</b>: a honeypot supplements, not replaces, perimeter controls.</span><span class='qd'><b>It automatically patches vulnerabilities</b>: honeypots observe attackers and do not patch systems.</span>" },
{ id:"D7-066", domain:7, obj:"7.8", diff:"easy", q:"What is the primary purpose of a patch management program?", options:["To add new marketing features","To identify, test, and deploy fixes for known software vulnerabilities in a controlled manner","To increase system CPU speed","To delete old user accounts"], answer:1, explain:"<strong>To identify, test, and deploy fixes for known software vulnerabilities in a controlled manner</strong> — patch management ensures security fixes are applied systematically to reduce exposure without breaking production.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To add new marketing features</b>: feature additions are product management, not the security purpose of patching.</span><span class='qd'><b>To increase system CPU speed</b>: patching addresses vulnerabilities and bugs, not raw performance.</span><span class='qd'><b>To delete old user accounts</b>: account cleanup is an identity task unrelated to patching.</span>" },
{ id:"D7-067", domain:7, obj:"7.8", diff:"medium", q:"A critical vendor patch is released. Before deploying it to all production servers, what should the organization do FIRST?", options:["Deploy it to every server immediately","Test the patch in a non-production environment to validate stability","Wait one year to be safe","Uninstall the affected application entirely"], answer:1, explain:"<strong>Test the patch in a non-production environment to validate stability</strong> — testing catches compatibility or stability problems before a broad rollout, balancing security urgency against operational risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deploy it to every server immediately</b>: untested patches can break production; even critical patches are validated first when feasible.</span><span class='qd'><b>Wait one year to be safe</b>: excessive delay leaves the known vulnerability exposed.</span><span class='qd'><b>Uninstall the affected application entirely</b>: removing needed software is disproportionate and disrupts the business.</span>" },
{ id:"D7-068", domain:7, obj:"7.8", diff:"medium", q:"A vulnerability scan produces hundreds of findings. Which factor should MOST influence the order in which they are remediated?", options:["Alphabetical order of the hostnames","Risk, based on severity/exploitability combined with asset criticality","The color of the report","The size of the log file"], answer:1, explain:"<strong>Risk, based on severity/exploitability combined with asset criticality</strong> — prioritizing by risk ensures the most dangerous, exploitable flaws on important assets are fixed first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Alphabetical order of the hostnames</b>: naming order has no relationship to security risk.</span><span class='qd'><b>The color of the report</b>: report formatting is irrelevant to remediation priority.</span><span class='qd'><b>The size of the log file</b>: log size does not reflect the danger of a vulnerability.</span>" },
{ id:"D7-069", domain:7, obj:"7.8", diff:"hard", q:"A legacy system runs a critical application but cannot be patched without breaking it, and the vendor no longer supports it. Which response is MOST appropriate?", options:["Ignore the risk since it cannot be patched","Connect it directly to the internet for convenience","Apply compensating controls such as isolation, strict monitoring, and virtual patching while planning migration","Disable all logging on the system"], answer:2, explain:"<strong>Apply compensating controls such as isolation, strict monitoring, and virtual patching while planning migration</strong> — when patching is impossible, layered compensating controls reduce exposure until the unsupported system can be replaced.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the risk since it cannot be patched</b>: unaddressed known vulnerabilities on a critical asset are unacceptable without controls.</span><span class='qd'><b>Connect it directly to the internet for convenience</b>: exposing an unpatchable system to the internet dramatically increases compromise likelihood.</span><span class='qd'><b>Disable all logging on the system</b>: removing logging eliminates the monitoring compensating controls depend on.</span>" },
{ id:"D7-070", domain:7, obj:"7.8", diff:"easy", q:"What is the key difference between a vulnerability scan and a patch?", options:["A scan identifies weaknesses; a patch is the fix that remediates a weakness","They are identical activities","A scan installs software; a patch removes it","A patch finds vulnerabilities; a scan applies fixes"], answer:0, explain:"<strong>A scan identifies weaknesses; a patch is the fix that remediates a weakness</strong> — scanning discovers vulnerabilities, while patching applies vendor updates to close them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are identical activities</b>: detection and remediation are distinct steps in the vulnerability lifecycle.</span><span class='qd'><b>A scan installs software; a patch removes it</b>: scanning does not install software, and patching typically updates rather than removes it.</span><span class='qd'><b>A patch finds vulnerabilities; a scan applies fixes</b>: this reverses the correct roles.</span>" },
{ id:"D7-071", domain:7, obj:"7.8", diff:"medium", q:"A CVSS score rates a vulnerability as 9.8 (Critical) with public exploit code, and the affected system is internet-facing and holds customer data. What should drive the remediation timeline?", options:["Waiting for the next quarterly patch cycle","Treating it as urgent given high severity, active exploitability, exposure, and data sensitivity","Ignoring CVSS scores entirely","Patching only if convenient"], answer:1, explain:"<strong>Treating it as urgent given high severity, active exploitability, exposure, and data sensitivity</strong> — a critical, exploitable flaw on an internet-facing system with sensitive data is high risk and warrants expedited, out-of-cycle remediation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Waiting for the next quarterly patch cycle</b>: delaying a critical, actively exploitable, internet-facing flaw invites compromise.</span><span class='qd'><b>Ignoring CVSS scores entirely</b>: CVSS with context is a valid input to prioritization.</span><span class='qd'><b>Patching only if convenient</b>: convenience is not an acceptable basis for a critical exposed vulnerability.</span>" },
{ id:"D7-072", domain:7, obj:"7.9", diff:"easy", q:"What is the primary purpose of a formal change management process?", options:["To allow anyone to modify production without review","To ensure changes are reviewed, approved, tested, and documented before implementation","To speed up changes by removing all approvals","To prevent any change from ever occurring"], answer:1, explain:"<strong>To ensure changes are reviewed, approved, tested, and documented before implementation</strong> — structured change management reduces the risk that a modification causes an outage or introduces a vulnerability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To allow anyone to modify production without review</b>: unreviewed changes are exactly the risk change management controls.</span><span class='qd'><b>To speed up changes by removing all approvals</b>: removing approvals sacrifices the oversight the process provides.</span><span class='qd'><b>To prevent any change from ever occurring</b>: the goal is to manage change safely, not block all change.</span>" },
{ id:"D7-073", domain:7, obj:"7.9", diff:"medium", q:"Which body typically reviews and approves proposed changes, weighing risk and impact before they proceed?", options:["Change advisory board (CAB)","Marketing committee","Payroll department","Facilities team"], answer:0, explain:"<strong>Change advisory board (CAB)</strong> evaluates proposed changes for risk, impact, and readiness, granting or denying approval before implementation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Marketing committee</b>: marketing does not assess technical change risk.</span><span class='qd'><b>Payroll department</b>: payroll handles compensation, not change approvals.</span><span class='qd'><b>Facilities team</b>: facilities manages buildings, not IT change governance.</span>" },
{ id:"D7-074", domain:7, obj:"7.9", diff:"medium", q:"A change to a production firewall causes an outage. Which element of a well-formed change request would have let the team quickly restore service?", options:["A documented rollback (back-out) plan","A longer meeting agenda","A larger email distribution list","A new logo"], answer:0, explain:"<strong>A documented rollback (back-out) plan</strong> defines how to revert the change and restore the prior working state quickly if the change fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A longer meeting agenda</b>: agenda length does nothing to restore a failed change.</span><span class='qd'><b>A larger email distribution list</b>: more recipients does not provide a technical recovery path.</span><span class='qd'><b>A new logo</b>: branding is irrelevant to reverting a firewall change.</span>" },
{ id:"D7-075", domain:7, obj:"7.9", diff:"hard", q:"A critical server is actively being exploited and requires an immediate configuration change outside normal CAB scheduling. How should a mature change process handle this?", options:["Refuse the change because CAB has not met","Use the emergency change procedure with expedited approval and retroactive documentation","Make the change with no record at all","Wait for the next quarterly CAB meeting"], answer:1, explain:"<strong>Use the emergency change procedure with expedited approval and retroactive documentation</strong> — mature processes include an emergency path that permits rapid action under urgent conditions while still capturing approval and records after the fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Refuse the change because CAB has not met</b>: rigidly blocking an urgent security fix causes greater harm.</span><span class='qd'><b>Make the change with no record at all</b>: undocumented changes defeat accountability.</span><span class='qd'><b>Wait for the next quarterly CAB meeting</b>: delaying a fix while an active exploit continues is unacceptable.</span>" },
{ id:"D7-076", domain:7, obj:"7.9", diff:"medium", q:"Which type of change is pre-approved because it is low-risk, well-understood, and follows a standard, repeatable procedure?", options:["Emergency change","Standard change","Normal change requiring full CAB","Unauthorized change"], answer:1, explain:"<strong>Standard change</strong> is a routine, low-risk change with a documented, repeatable procedure that is pre-authorized, so it does not require full CAB review each time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Emergency change</b>: an emergency change is unplanned and urgent, not pre-approved routine work.</span><span class='qd'><b>Normal change requiring full CAB</b>: a normal change goes through full assessment and CAB.</span><span class='qd'><b>Unauthorized change</b>: an unauthorized change bypasses the process and is never pre-approved.</span>" },
{ id:"D7-077", domain:7, obj:"7.10", diff:"easy", q:"Which RAID level provides disk mirroring, writing identical copies of data to two drives for fault tolerance?", options:["RAID 0","RAID 1","RAID 5","RAID 6"], answer:1, explain:"<strong>RAID 1</strong> mirrors data across two drives so that if one fails, the other still holds a complete copy, providing fault tolerance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID 0</b>: RAID 0 stripes data for performance with no redundancy, so one drive failure loses all data.</span><span class='qd'><b>RAID 5</b>: RAID 5 uses striping with distributed parity across three or more disks, not simple mirroring.</span><span class='qd'><b>RAID 6</b>: RAID 6 uses double distributed parity, not mirroring.</span>" },
{ id:"D7-078", domain:7, obj:"7.10", diff:"medium", q:"An administrator needs an array that stripes data with distributed parity, tolerates a single disk failure, and uses storage efficiently across four disks. Which RAID level fits BEST?", options:["RAID 0","RAID 1","RAID 5","RAID 10"], answer:2, explain:"<strong>RAID 5</strong> stripes data with distributed parity across three or more disks, tolerating one drive failure while using capacity more efficiently than mirroring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RAID 0</b>: RAID 0 has no parity or redundancy, so any disk failure loses data.</span><span class='qd'><b>RAID 1</b>: RAID 1 mirrors and consumes half the raw capacity, less storage-efficient than distributed parity.</span><span class='qd'><b>RAID 10</b>: RAID 10 mirrors then stripes at 50% capacity overhead, less efficient than RAID 5.</span>" },
{ id:"D7-079", domain:7, obj:"7.15", diff:"medium", q:"An executive traveling to a high-risk country is issued a clean loaner laptop with minimal data and told not to connect to untrusted networks. Which concern is this practice MOST addressing?", options:["Marketing outreach","Reducing baggage weight","Improving airline loyalty points","Protecting sensitive data and devices from compromise or seizure during travel"], answer:3, explain:"<strong>Protecting sensitive data and devices from compromise or seizure during travel</strong> — travel security uses minimally provisioned devices so that theft, seizure, or hostile networks expose little of value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Marketing outreach</b>: marketing is unrelated to protecting devices during risky travel.</span><span class='qd'><b>Reducing baggage weight</b>: a loaner laptop is a security measure, not a luggage optimization.</span><span class='qd'><b>Improving airline loyalty points</b>: loyalty programs have nothing to do with data protection on travel.</span>" },
{ id:"D7-080", domain:7, obj:"7.10", diff:"medium", q:"An organization wants to guarantee that no more than 15 minutes of data can be lost if a system fails. Which metric does this define?", options:["Recovery time objective (RTO)","Recovery point objective (RPO)","Maximum tolerable downtime (MTD)","Mean time between failures (MTBF)"], answer:1, explain:"<strong>Recovery point objective (RPO)</strong> defines the maximum acceptable amount of data loss measured in time, so a 15-minute RPO drives backup or replication frequency.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recovery time objective (RTO)</b>: RTO is how quickly service must be restored, not how much data may be lost.</span><span class='qd'><b>Maximum tolerable downtime (MTD)</b>: MTD is the longest a function can be down before unacceptable harm.</span><span class='qd'><b>Mean time between failures (MTBF)</b>: MTBF is a reliability statistic, not a recovery target.</span>" },
{ id:"D7-081", domain:7, obj:"7.10", diff:"medium", q:"A backup strategy performs a full backup weekly and captures only the data changed since the last full backup each night. Which backup type is the nightly job?", options:["Incremental backup","Differential backup","Snapshot only","Full backup"], answer:1, explain:"<strong>Differential backup</strong> captures everything changed since the last full backup, so restoring requires only the last full plus the latest differential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incremental backup</b>: an incremental captures changes since the last backup of any type, not since the last full.</span><span class='qd'><b>Snapshot only</b>: a snapshot is a point-in-time image, not the described change-since-full scheme.</span><span class='qd'><b>Full backup</b>: a full backup copies all data every time, which the nightly job does not.</span>" },
{ id:"D7-082", domain:7, obj:"7.15", diff:"hard", q:"A departing employee with privileged access has shown signs of disgruntlement. Which combination of controls BEST mitigates insider-threat risk during offboarding?", options:["Wait a few weeks before removing access to be polite","Immediately disable access upon notice, conduct an exit interview, and review recent privileged activity","Give the employee extra access as a goodbye gesture","Do nothing since they are leaving anyway"], answer:1, explain:"<strong>Immediately disable access upon notice, conduct an exit interview, and review recent privileged activity</strong> — prompt deprovisioning closes the window for retaliation, while the exit interview and activity review detect any data theft or sabotage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wait a few weeks before removing access to be polite</b>: delaying removal leaves a disgruntled insider with dangerous access.</span><span class='qd'><b>Give the employee extra access as a goodbye gesture</b>: expanding access to a disgruntled leaver is the opposite of risk reduction.</span><span class='qd'><b>Do nothing since they are leaving anyway</b>: inaction ignores the heightened insider-threat risk that departure creates.</span>" },
{ id:"D7-083", domain:7, obj:"7.10", diff:"medium", q:"An e-commerce site must remain available even if one server fails, with no noticeable interruption to customers. Which strategy BEST meets this need?", options:["A single powerful server","High-availability clustering with automatic failover","Nightly tape backups only","A cold spare in storage"], answer:1, explain:"<strong>High-availability clustering with automatic failover</strong> keeps redundant nodes ready so that if one fails, another takes over seamlessly with minimal or no downtime.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single powerful server</b>: one server is a single point of failure regardless of its power.</span><span class='qd'><b>Nightly tape backups only</b>: tape backups enable recovery but not continuous availability during a failure.</span><span class='qd'><b>A cold spare in storage</b>: a cold spare must be manually installed and configured, causing downtime.</span>" },
{ id:"D7-084", domain:7, obj:"7.10", diff:"easy", q:"Following the 3-2-1 backup rule, how many total copies of data should exist and how many should be off-site?", options:["Three copies, on two media types, with one off-site","One copy, on one medium, all on-site","Two copies, both off-site, on one medium","Three copies, all on the same server"], answer:0, explain:"<strong>Three copies, on two media types, with one off-site</strong> — the 3-2-1 rule ensures redundancy across media and geography so a single failure or site disaster does not destroy all copies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One copy, on one medium, all on-site</b>: a single on-site copy has no redundancy or disaster protection.</span><span class='qd'><b>Two copies, both off-site, on one medium</b>: this omits an on-site working copy and uses only one medium.</span><span class='qd'><b>Three copies, all on the same server</b>: co-locating all copies defeats redundancy.</span>" },
{ id:"D7-085", domain:7, obj:"7.11", diff:"easy", q:"Which disaster recovery site is fully equipped with hardware, software, and current data, ready to take over operations within minutes to hours?", options:["Cold site","Warm site","Hot site","Mobile site"], answer:2, explain:"<strong>Hot site</strong> is a fully operational duplicate with current data and running systems, enabling near-immediate failover at the highest cost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cold site</b>: a cold site is only space and utilities with no ready equipment, requiring days or weeks.</span><span class='qd'><b>Warm site</b>: a warm site has hardware and connectivity but not fully current data.</span><span class='qd'><b>Mobile site</b>: a mobile site is a transportable facility and is not by definition fully equipped and current.</span>" },
{ id:"D7-086", domain:7, obj:"7.11", diff:"easy", q:"Which recovery site provides only space, power, and cooling with no pre-installed IT equipment, making it the cheapest but slowest to activate?", options:["Hot site","Warm site","Cold site","Cloud site"], answer:2, explain:"<strong>Cold site</strong> offers only the facility and utilities, so it is the least expensive to maintain but requires the most time to procure and install equipment before recovery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hot site</b>: a hot site is fully equipped and ready, making it the fastest and most expensive.</span><span class='qd'><b>Warm site</b>: a warm site has some equipment pre-installed, so it activates faster than a cold site.</span><span class='qd'><b>Cloud site</b>: a cloud recovery option can be provisioned quickly and is not merely empty space.</span>" },
{ id:"D7-087", domain:7, obj:"7.11", diff:"medium", q:"An organization needs a recovery site that has hardware and network connectivity in place but relies on restoring recent backups to become operational, balancing cost against recovery speed. Which site type fits?", options:["Hot site","Warm site","Cold site","No recovery site"], answer:1, explain:"<strong>Warm site</strong> has pre-installed hardware and connectivity but needs data restored from backups to go live, offering a middle ground between the cost of a cold site and the speed of a hot site.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hot site</b>: a hot site already has current data and needs no backup restore, at higher cost.</span><span class='qd'><b>Cold site</b>: a cold site lacks the pre-installed hardware the scenario specifies.</span><span class='qd'><b>No recovery site</b>: having no site fails to meet any recovery objective.</span>" },
{ id:"D7-088", domain:7, obj:"7.11", diff:"hard", q:"A company with a very short RTO but a limited budget is choosing a recovery site. Which trade-off analysis MOST correctly guides the decision?", options:["Choose a cold site because it is cheapest regardless of RTO","Recognize that shorter RTO generally demands a hotter (costlier) site, then balance cost against the RTO the business truly requires","Always choose a hot site regardless of need","RTO has no bearing on site selection"], answer:1, explain:"<strong>Recognize that shorter RTO generally demands a hotter (costlier) site, then balance cost against the RTO the business truly requires</strong> — recovery speed and cost trade off directly, so the site choice must reconcile the required RTO with the available budget.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choose a cold site because it is cheapest regardless of RTO</b>: a cold site's long activation likely violates a very short RTO.</span><span class='qd'><b>Always choose a hot site regardless of need</b>: over-provisioning wastes budget when a lesser site could meet the RTO.</span><span class='qd'><b>RTO has no bearing on site selection</b>: RTO is a primary driver of site type.</span>" },
{ id:"D7-089", domain:7, obj:"7.11", diff:"medium", q:"Two organizations agree to host each other's operations in the event of a disaster at either site. What is this arrangement called?", options:["Reciprocal (mutual aid) agreement","Service level agreement","Nondisclosure agreement","Master service agreement"], answer:0, explain:"<strong>Reciprocal (mutual aid) agreement</strong> is a low-cost arrangement where two organizations agree to support each other's processing during a disaster, though it depends on the partner having spare capacity and compatible systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Service level agreement</b>: an SLA defines service performance commitments, not mutual disaster hosting.</span><span class='qd'><b>Nondisclosure agreement</b>: an NDA governs confidentiality, not recovery hosting.</span><span class='qd'><b>Master service agreement</b>: an MSA sets overarching contract terms, not a reciprocal recovery pact.</span>" },
{ id:"D7-090", domain:7, obj:"7.11", diff:"medium", q:"When selecting an alternate recovery site, why should it be located a sufficient distance from the primary site?", options:["To reduce shipping costs","So a regional disaster affecting the primary site does not also disable the recovery site","To use the same power grid","To keep both sites on one flood plain"], answer:1, explain:"<strong>So a regional disaster affecting the primary site does not also disable the recovery site</strong> — geographic separation ensures a single event such as a flood, earthquake, or grid failure will not take out both locations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To reduce shipping costs</b>: logistics cost is secondary to surviving a regional disaster.</span><span class='qd'><b>To use the same power grid</b>: sharing a grid is a liability, since one grid failure could hit both sites.</span><span class='qd'><b>To keep both sites on one flood plain</b>: placing both on the same flood plain defeats separation.</span>" },
{ id:"D7-091", domain:7, obj:"7.15", diff:"medium", q:"An organization implements ongoing behavioral monitoring, mandatory reporting of concerns, and periodic re-screening for staff in sensitive roles. Which risk are these controls PRIMARILY managing?", options:["Insider threat","Weather disasters","Network latency","Software licensing costs"], answer:0, explain:"<strong>Insider threat</strong> — continuous evaluation, reporting channels, and re-screening are designed to detect and deter trusted personnel who might misuse their access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Weather disasters</b>: environmental events are addressed by continuity and facility controls, not personnel monitoring.</span><span class='qd'><b>Network latency</b>: latency is a performance issue, unrelated to personnel security programs.</span><span class='qd'><b>Software licensing costs</b>: licensing is a procurement matter, not an insider-threat control.</span>" },
{ id:"D7-092", domain:7, obj:"7.15", diff:"medium", q:"An organization requires background re-investigation and continuous evaluation for employees who hold the most sensitive access. What is the PRIMARY goal of these personnel security measures?", options:["To reduce insider-threat risk by detecting concerning changes in trusted staff over time","To speed up software deployments","To lower cloud storage costs","To improve office ergonomics"], answer:0, explain:"<strong>To reduce insider-threat risk by detecting concerning changes in trusted staff over time</strong> — periodic re-investigation and continuous evaluation catch financial, behavioral, or legal red flags that may indicate a person in a sensitive role has become a risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To speed up software deployments</b>: deployment velocity is unrelated to personnel vetting.</span><span class='qd'><b>To lower cloud storage costs</b>: storage cost is a technical/financial matter, not a personnel-security goal.</span><span class='qd'><b>To improve office ergonomics</b>: ergonomics concerns workplace comfort, not insider-threat detection.</span>" },
{ id:"D7-093", domain:7, obj:"7.12", diff:"easy", q:"Which DRP test involves participants talking through the recovery plan step by step in a conference room without activating any systems?", options:["Full interruption test","Parallel test","Tabletop (walkthrough) exercise","Simulation with live failover"], answer:2, explain:"<strong>Tabletop (walkthrough) exercise</strong> gathers stakeholders to discuss and validate the recovery plan verbally, surfacing gaps without touching production systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full interruption test</b>: a full interruption actually stops production and fails over, far beyond a discussion.</span><span class='qd'><b>Parallel test</b>: a parallel test brings up the recovery site alongside production, which a tabletop does not.</span><span class='qd'><b>Simulation with live failover</b>: live failover activates systems, unlike a talk-through exercise.</span>" },
{ id:"D7-094", domain:7, obj:"7.12", diff:"medium", q:"Which DRP test brings the recovery systems online and processes real workloads in parallel with production WITHOUT taking production offline?", options:["Tabletop exercise","Parallel test","Full interruption test","Checklist review"], answer:1, explain:"<strong>Parallel test</strong> activates the recovery environment and runs it alongside production to verify it works, while production continues serving users, avoiding disruption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tabletop exercise</b>: a tabletop is discussion only and does not bring systems online.</span><span class='qd'><b>Full interruption test</b>: a full interruption shifts production to recovery and takes production offline.</span><span class='qd'><b>Checklist review</b>: a checklist review only verifies documentation, not live parallel processing.</span>" },
{ id:"D7-095", domain:7, obj:"7.12", diff:"hard", q:"Which DRP test carries the HIGHEST risk to the business because production is actually shut down and operations are shifted entirely to the recovery site?", options:["Checklist review","Structured walkthrough","Full interruption test","Tabletop exercise"], answer:2, explain:"<strong>Full interruption test</strong> stops production and moves all operations to the recovery site, providing the most realistic validation but the greatest risk of a real outage if recovery fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Checklist review</b>: a checklist review only inspects documentation and carries essentially no operational risk.</span><span class='qd'><b>Structured walkthrough</b>: a walkthrough discusses the plan and does not disrupt production.</span><span class='qd'><b>Tabletop exercise</b>: a tabletop is discussion-based with no live cutover.</span>" },
{ id:"D7-096", domain:7, obj:"7.12", diff:"medium", q:"An organization has never tested its DRP and wants to start with the lowest-risk validation to confirm the plan documents are complete and up to date. Which test should it begin with?", options:["Full interruption test","Checklist (read-through) review","Parallel test","Live failover"], answer:1, explain:"<strong>Checklist (read-through) review</strong> is the least disruptive test, verifying that plan documents, contacts, and resources are complete and current before more intensive testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full interruption test</b>: a full interruption is the riskiest test and is inappropriate as a first step.</span><span class='qd'><b>Parallel test</b>: a parallel test is more involved and premature before basic documentation is validated.</span><span class='qd'><b>Live failover</b>: live failover disrupts or risks production and is far beyond a first-step review.</span>" },
{ id:"D7-097", domain:7, obj:"7.12", diff:"medium", q:"An organization conducts a tabletop of its DR plan and discovers the emergency contact list is a year out of date. What does this outcome demonstrate about testing?", options:["Testing is a waste of time","Even low-impact tests reveal critical gaps that would cause failure during a real disaster","Only full interruption tests find problems","The plan is perfect"], answer:1, explain:"<strong>Even low-impact tests reveal critical gaps that would cause failure during a real disaster</strong> — a simple tabletop surfaced a stale contact list that could cripple response, showing the value of regular, even lightweight, testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Testing is a waste of time</b>: the test just prevented a real failure, proving its worth.</span><span class='qd'><b>Only full interruption tests find problems</b>: a tabletop found a serious gap without any interruption.</span><span class='qd'><b>The plan is perfect</b>: the discovery of an outdated list proves the plan had a flaw.</span>" },
{ id:"D7-098", domain:7, obj:"7.13", diff:"easy", q:"What is the PRIMARY difference between business continuity planning (BCP) and disaster recovery planning (DRP)?", options:["BCP focuses on keeping critical business functions running; DRP focuses on restoring IT systems and infrastructure","They are identical","DRP addresses business functions and BCP addresses IT only","BCP applies only to marketing"], answer:0, explain:"<strong>BCP focuses on keeping critical business functions running; DRP focuses on restoring IT systems and infrastructure</strong> — BCP is the broader strategy for continuing operations, while DRP is the IT-recovery component nested within it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are identical</b>: BCP and DRP have distinct, complementary scopes.</span><span class='qd'><b>DRP addresses business functions and BCP addresses IT only</b>: this reverses the correct scopes.</span><span class='qd'><b>BCP applies only to marketing</b>: BCP covers all critical business functions, not just marketing.</span>" },
{ id:"D7-099", domain:7, obj:"7.13", diff:"medium", q:"Which analysis identifies an organization's critical business functions and the impact over time of their disruption, driving continuity priorities?", options:["Business impact analysis (BIA)","Penetration test","Threat model","Data flow diagram"], answer:0, explain:"<strong>Business impact analysis (BIA)</strong> identifies critical functions, their dependencies, and the escalating impact of downtime, providing the basis for RTOs, RPOs, and recovery priorities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Penetration test</b>: a pen test evaluates exploitable weaknesses, not business-function criticality over time.</span><span class='qd'><b>Threat model</b>: threat modeling enumerates threats to a system, not organization-wide continuity impacts.</span><span class='qd'><b>Data flow diagram</b>: a data flow diagram maps how data moves, not the impact of function disruption.</span>" },
{ id:"D7-100", domain:7, obj:"7.13", diff:"hard", q:"Senior management questions why continuity planning needs their sponsorship rather than being handled solely by IT. What is the BEST justification?", options:["Continuity is purely a technical IT concern","Business continuity spans people, processes, facilities, and funding decisions that require executive authority and enterprise-wide buy-in","Only the IT manager can approve budgets","Continuity planning does not require any resources"], answer:1, explain:"<strong>Business continuity spans people, processes, facilities, and funding decisions that require executive authority and enterprise-wide buy-in</strong> — because continuity crosses every business unit and demands resource commitments, it must be owned and championed at the executive level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Continuity is purely a technical IT concern</b>: continuity is an enterprise-wide concern encompassing far more than IT.</span><span class='qd'><b>Only the IT manager can approve budgets</b>: enterprise continuity funding exceeds a single IT manager's authority.</span><span class='qd'><b>Continuity planning does not require any resources</b>: continuity requires significant people, facilities, and funding.</span>" }
);
